var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당장 위협이 되는 것들은 전부 정리한 것 같네요.","JPN":"いったん危険になりそうなものは全部片付けたようです。","ENG":"Looks like we took care of any imminent threats.","TWN":"眼前的威脅已經解決好了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"후아…","JPN":"はあ……","ENG":"Huah...","TWN":"呼……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"지나온 길이 전부 기름 두른 프라이팬처럼 끓고 있어요.","JPN":"通ってきた道が油を入れたフライパンのように焼けています。","ENG":"The path is sizzling like a preheated frying pan.","TWN":"我們走來的路像一個燒油的鍋一樣沸騰。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"한 대라도 맞았으면 계란프라이가 됐겠죠?","JPN":"一回でも当たったら目玉焼きになったでしょうね。","ENG":"One hit and SPLAT! We would've looked like someone's fried eggs for breakfast, right?","TWN":"要是被打中，會變成荷包蛋吧？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"스완이란 사람, 혼자서 제법 대단한 일을 벌였네요.","JPN":"スワンという人、たった一人で凄いことをするんですね。","ENG":"This Swan person... She's done quite a lot on her own.","TWN":"這個叫史旺的傢伙，一個人做了這麼多不得了的事情。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"세상을 위험하게 만드는 봉인을 풀고, 우리가 올 걸 예상까지 하다니.","JPN":"世界を危険にさらす封印を解いて、私たちが来ることも予想するとは。","ENG":"She's removed the seal that puts the world in danger and predicted that we'll come.","TWN":"不僅打破了會使世界處於危險的封印，還預知了我們的到來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"스완이 어떤 마술을 부렸는지는 저 방주 안으로 진입하면 알 수 있겠지.","JPN":"スワンがどんな仕業をしたのかはあの箱舟の中に侵入すればわかるだろう。","ENG":"I guess we'll see what kind of witchery she used after we infiltrate that Ark.","TWN":"等我們進入方舟，就會知道史旺到底施了什麼魔法。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 조심하게.","JPN":"だが、気を付けたまえ。","ENG":"Careful.","TWN":"但要小心。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"봉인이 대부분 해제된 방주의 내부는 이미 클리파 차원과 동화된 상태나 다름없을 테니까.","JPN":"封印がほぼ解かれた箱舟の中は既にクリファ次元と同化したような状態のはずだ。","ENG":"With the seal mostly removed, the inside of that Ark is likely to be synced with the Qlipha Dimension.","TWN":"方舟內部大部分封印已經解除，可能幾乎是與逆卡巴拉次元同化的狀態。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"클리파 차원이라니… 그게 대체 뭔가요?","JPN":"クリファ次元って……それは一体なんですか？","ENG":"Qlipha Dimension...? What is that?","TWN":"逆卡巴拉次元…….那是什麼東西？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무너진 세계와 이어지는 통로.","JPN":"崩壊した世界に繋がる道。","ENG":"A tunnel linked to a destroyed world.","TWN":"與崩潰的世界連通的通道。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마왕의 강대한 힘을 현실로 끌어들일 만큼, 거대하면서도 불안정한…","JPN":"魔王の強力な力を現実に引き込むことができる、巨大ながらも不安定な……","ENG":"It has the power to bring the Demon Lord's potent powers into the Normalside. It's a massive, yet unstable...","TWN":"足以將魔王之力引入現實的強大又不穩定的……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가능성의 영역이지.","JPN":"可能性の領域だ。","ENG":"...area of possibilities.","TWN":"可能性之領域。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양.","JPN":"ミナ君。","ENG":"Mina.","TWN":"米娜。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응?","JPN":"あ？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"만약 일이 잘못되어가고 있다고 느꼈을 땐, 날 믿고 하늘을 올려다보지 말게.","JPN":"もし何か間違っていると感じた時は、私を信じて空を見上げないようにしてくれ。","ENG":"If you feel that things are going wrong, trust me and don't look up into the sky.","TWN":"當你覺得事情不對勁，相信我，不要抬頭。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"두 사람도 미나 양 말이라면 따를 테니 말해두는 걸세.","JPN":"二人もミナ君の話なら従うはずだから、言っておく。","ENG":"I'm telling you since the other two will follow whatever you say.","TWN":"我和你說這些是因為另外兩個人都會聽從你的話。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…뭔진 모르겠지만 영 불안해지는 얘기네.","JPN":"……何のことかわからないけど、不安になる話だね。","ENG":"...I don't really get it, but it doesn't sound good.","TWN":"……雖然不知道是什麼，聽起來有些令人不安呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그러니까 나한테만 말해둔다는 거지? 알겠어.","JPN":"だから、私にだけ言っておくということだね？　わかったよ。","ENG":"That's why I'm the only one you're telling, right? Okay.","TWN":"所以你只對我說了這些，對嗎？好吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이해해줘서 고맙네.","JPN":"理解してくれてありがとう。","ENG":"Thank you for understanding.","TWN":"謝謝理解。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼… 들어가자.","JPN":"じゃ……入ろう。","ENG":"Then... Let's go in.","TWN":"那麼……我們開始吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"어서 오게.","JPN":"ようこそ。","ENG":"Welcome.","TWN":"歡迎光臨。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"너무 늦지도, 이르지도 않게 등장해주었군.","JPN":"遅くも早くもない登場だな。","ENG":"You arrived just on time. It's not too late or too early.","TWN":"來得剛剛好。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 이걸로 함선의 시스템을 속인 건가?","JPN":"やはりこれで艦船のシステムを騙したのか？","ENG":"Is this how she fooled the ship's system?","TWN":"你就是這樣騙過艦船的安全系統的？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"시윤 군이 스완의 능력에 대해 경고해주긴 했지만…","JPN":"シリュウ君がスワンの能力について警告してくれたが……","ENG":"Shiyoon did give me a heads up about Swan's abilities, but...","TWN":"時雲警告過史旺的能力，但……"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"한번 본 것만으로 날 완벽하게 복제할 줄은 몰랐군.","JPN":"一度見ただけで私を完璧にコピーできるとは思わなかった。","ENG":"I would've never guessed she could clone me so perfectly after just seeing me once.","TWN":"沒想到只是看一眼就能完美複製我。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"스완이 가진 모방 능력은 겉모습만을 훔칠 뿐이지.","JPN":"スワンが持っている模倣能力は外見を真似るだけだな。","ENG":"Swan's imitation ability only steals one's appearance.","TWN":"史旺的模仿能力只限於外表。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"하지만 이 함선 내부는 이미 클리파에 잠식된 상태일세.","JPN":"しかしこの艦船の内部は既にクリファに侵食された状態。","ENG":"But the inside of this ship is already consumed by Qlipha.","TWN":"不過這艘艦船的內部已經被逆卡巴拉侵蝕了。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"클리파 차원 속에선 상상이 현실이 되기도 한다는 걸 자네도 알고 있잖나?","JPN":"クリファ次元の中では想像が現実になりうることを、君も知っているだろう？","ENG":"I'm sure you already know that within the Qlipha Dimension, imagination can become reality, right?","TWN":"你應該也知道，在逆卡巴拉次元裡任何想像都可以成為現實。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"그러니 난 그녀가 자네에 대해 아는 정보와 견해로 만들어진 복제품이라 할 수 있지.","JPN":"だから私は彼女が君について知っている情報と見解で作られたコピーと言える。","ENG":"So you can say that I'm a replica of you made from what she knows about you and her impression.","TWN":"所以可以說我是根據她對你的情報和見解製作而成的複製品。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"나 자신과 이야기하는 건… 확실히 어색한 경험이군.","JPN":"自分と話すのは……確かに気まずい経験だな。","ENG":"Talking to myself is... definitely an awkward experience.","TWN":"和自己對話……確實難以適應。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"관중으로 불러낸 날 굳이 자신과 마주하게 하는 이유가 뭐지?","JPN":"観客として呼んだ私にわざわざコピーを送りつけた理由はなんだ？","ENG":"Why would she assign me as her audience and make me talk to myself?","TWN":"為什麼要讓我這個觀眾面對自己？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"스완에겐 마지막 봉인의 열쇠가 <color=#ffd34c>그것</color>이라는 확신이 필요했거든.","JPN":"スワンには最後の封印の鍵が<color=#ffd34c>あれ</color>だという確信が必要だったんだ。","ENG":"That's because Swan needed to be sure that the key to the last seal was <color=#ffd34c>it</color>.","TWN":"史旺需要確定最後的封印鑰匙是<color=#ffd34c>那個東西</color>。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"이곳은 파노라마라 불리는 스완의 거울 아티팩트 속일세.","JPN":"ここはパノラマという、スワンの鏡のアーティファクトの中なのだ。","ENG":"This place is inside Swan's mirror Artifact called Panorama.","TWN":"這裡是全景，是史旺的鏡子人造神器內部。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"시간이 멈춘 이곳에선 거울이 투영한 나 자신을 꺾어야만 거울을 벗어날 수 있지.","JPN":"時間が止まったここでは鏡が映している自分自身に勝たなければ脱出できない。","ENG":"Time doesn't flow here, and the only way to escape is to defeat the reflection of yourself in the mirror.","TWN":"在這個時間靜止的地方，你只有打敗鏡子中的倒影才能逃離鏡子。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"지금 나보고 나 자신과 싸우라는 건가?","JPN":"私に自分自身と戦えと言っているのか？","ENG":"You want me to fight myself?","TWN":"你是讓我和我自己戰鬥？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"난 나 자신을 사랑하기 때문에 그렇게 할 수 없네.","JPN":"私は自分を愛しているから、そんなことはできない。","ENG":"I can't because I simply love myself too much.","TWN":"我做不到，因為我愛我自己。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"같은 힘을 가진 상대를 이기라니, 상식적으로 불가능한 일이군.","JPN":"同じ力を持っている相手に勝てとは、常識的に考えて不可能なことだな。","ENG":"Defeating an opponent of equal strength. That is undoubtedly impossible.","TWN":"從常理上講，我不可能擊敗擁有與我相同力量的對手。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"그렇게 할 수 없다면, 스완이 원하는 대답을 해야겠지.","JPN":"できないなら、スワンが望む答えを出さなければなるまい。","ENG":"If you can't, then you must give Swan the answer she wants.","TWN":"如果做不到，你就得給史旺她想要的答案。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"클리파 차원에 거울이 하나만 있을 거라고 생각말게.","JPN":"クリファ次元の中にある鏡が一つだけとは考えない方がいい。","ENG":"And don't think that there is only one mirror in the Qlipha Dimension.","TWN":"別以為逆卡巴拉次元裡只有一面鏡子。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"이미 수많은 나를 상대로 똑같은 질문을 하고 있을 테니 거짓말은 소용 없을 걸세.","JPN":"すでに多くの自分を相手に同じ質問をしているはずだから、嘘は何の意味もないだろう。","ENG":"Lying won't work, as I will be asking the same question across countless mirrors.","TWN":"她可能已經對無數個我提出了相同的問題，所以撒謊應該是沒用的。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"스완이 클리파 차원에서 일어나는 모든 가능성을 관측하고 있는 건가?","JPN":"スワンはクリファ次元で発生している全ての可能性を観察しているのか？","ENG":"Are you saying that Swan is observing all the possibilities that could happen within the Qlipha Dimension?","TWN":"你是說史旺在觀察逆卡巴拉次元中發生的所有可能性？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 이곳에서 무슨 대답을 하건, 스완은 원하는 답을 듣게 되겠군.","JPN":"ここで私が何を言っても、スワンは望む答えを聞けるってわけか。","ENG":"Then regardless of what I say here, Swan will get the answer she desires.","TWN":"不管我在這裡說什麼，史旺都會得到她想要的答案。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"마지막 봉인의 열쇠는 엘리시온의 위대한 정적이 가진 성흔의 에너지 패턴일세.","JPN":"最後の封印の鍵はエリシオンの偉大なる静寂が持っている聖痕エネルギーのパターンだ。","ENG":"The last key to the seal is the energy pattern of the Stigmata owned by the Great Silence of Elysion.","TWN":"最後一個封印鑰匙是艾利森偉大的寂靜擁有的聖痕能量模型。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"그렇다면 어째서 이미 그림자로 전락해버린 인간을 봉인의 열쇠로 선택한 거지?","JPN":"ならばどうして既にシャドウとなってしまった人間を封印の鍵として選択したんだ？","ENG":"Then, why did you choose a human who had already turned into a Shadow as the key to the seal?","TWN":"為什麼要選擇一個已經化為暗影的人類作為封印的鑰匙呢？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"훗날 완전해진 얼터니움으로 모르스를 되돌려 타기리온에게 대적하기 위함이었지.","JPN":"いつの日か完全になるオルタニウムでモールスを元に戻し、タギリオンと戦わせるためだった。","ENG":"It was to, one day, change back Mors with the completed Alternium so she could fight Thagirion.","TWN":"為了日後使用完整的黑化永恆之金找回死神，對抗塔基里翁。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"훗날 완전해진 얼터니움으로 모르스를 되돌려 타기리온에게 대적하기 위함이었지.","JPN":"いつの日か完全になるオルタニウムでモールスを元に戻し、タギリオンと戦わせるためだった。","ENG":"It was to, one day, change back Mors with the completed Alternium so she could fight Thagirion.","TWN":"為了日後使用完整的黑化永恆之金找回死神，對抗塔基里翁。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"훗날 완전해진 얼터니움으로 모르스를 되돌려 타기리온에게 대적하기 위함이었지.","JPN":"いつの日か完全になるオルタニウムでモールスを元に戻し、タギリオンと戦わせるためだった。","ENG":"It was to, one day, change back Mors with the completed Alternium so she could fight Thagirion.","TWN":"為了日後使用完整的黑化永恆之金找回死神，對抗塔基里翁。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"그래, 솔직하게 말해줘서 고맙네.","JPN":"そうか、素直に答えてくれてありがとう。","ENG":"All right. Thank you for your honesty.","TWN":"好吧，謝謝你坦誠回答。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_MIRROR","text":{"KOREA":"멈춘 시간에 갇혀 만 년이 넘도록 침묵하는 경우도 있었지만, 적어도 나의 세 가지 가능성은 같은 대답을 해줬군.","JPN":"止まった時間に閉じ込められて一万年以上沈黙しているときもあったが、少なくとも私の三つの可能性は同じ答えを出してくれた。","ENG":"There was a version of you that kept your silence for ten thousand years in frozen time. But at least my three possibilities gave me the same answer.","TWN":"也可能會被困在永恆的時間裡沉默千萬年，但至少我的三種可能性給出了相同的答案。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"사실 검증이 끝났으면 이 답답한 공간에서 날 좀 꺼내주겠나?","JPN":"事実の検証が済んだのならば、この窮屈な空間から出してくれないか？","ENG":"If you're done with fact-checking, could you let me out of this stuffy place?","TWN":"既然你已經驗證了事實，能不能請你讓我離開這個發悶的地方？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원하는 답을 얻기 위해 사람을 만 년씩이나 가둬 두다니, 지독한 발상이군.","JPN":"望む答えを手にするために人を一万年も閉じ込めておくとは、酷いやり方だな。","ENG":"Trapping someone in there for ten thousand years just to get the answer you want. What a wicked idea.","TWN":"為了得到想要的答案而把人關上一萬年，真是個糟糕的主意。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"실례했어요.","JPN":"失礼しました。","ENG":"Pardon me.","TWN":"打擾了。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그건 어차피 당신이 겪게 될 가능성 중 하나였을 뿐인 걸요.","JPN":"でもそれはあなたが経験するであろう可能性の一つに過ぎません。","ENG":"But that was merely one of the possibilities that you could have experienced.","TWN":"但無論如何，這只是你會遇到的可能性之一。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제아무리 당신이라도 실제로 그런 일을 겪었다면 미쳐버렸겠지만, 지금은 멀쩡하잖아요?","JPN":"さすがのあなたでも実際にそんな経験をしたら精神が崩壊してしまうかもしれませんが、今は平気でしょう？","ENG":"Even you would have gone insane if you had gone through that. But look at you now. You're just fine.","TWN":"如果發生在你身上，你一定會瘋掉吧。但你現在沒事不是嗎？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"클리파 차원을 이런 식으로 이용하는 건, 카운터가 아니라 마왕의 권능에 가까워보이는데.","JPN":"クリファ次元をこんな風に利用するのは、カウンターではなく魔王の権能に近いように見えるが。","ENG":"Manipulating the Qlipha Dimension like this seems closer to the powers of a Demon Lord than a Counter.","TWN":"以這種方式使用逆卡巴拉次元似乎更像是魔王的權能，而不是制裁者。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…맞아요. 타기리온과 계약해서 힘을 빌렸죠.","JPN":"……そうです。タギリオンと契約して力を借りました。","ENG":"...You're right. I made a deal with Thagirion to borrow her strength.","TWN":"……沒錯，我和塔基里翁簽訂了契約，借用了她的力量。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 목적을 달성하려면 그녀를 이곳에 끌어들여야 했으니까요.","JPN":"私の目的を達成するためには、彼女をここに誘い込む必要がありますから。","ENG":"I need her here in order to fulfill my objective.","TWN":"為了達成目的，我必須把她引到這裡。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이제 날 어떻게 할 셈이지?","JPN":"それで、私をどうするつもりだ？","ENG":"So what are you going to do with me now?","TWN":"你現在打算拿我怎麼辦？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"앞서 약속드렸다시피 관중으로서 예우해드릴 겁니다.","JPN":"先ほど約束したように観客として礼遇します。","ENG":"As promised, I'll treat you like the audience.","TWN":"正如我之前承諾的那樣，你將是這場演出的觀眾。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어차피 지금부터 당신은 다른 사람들을 지켜보는 것 말곤 아무것도 할 수 없을 테니까요.","JPN":"いずれにせよ今からあなたは他の人を見守ることしか、できることはないでしょう。","ENG":"But even then, all you will be able to do is watch the others from the sidelines.","TWN":"反正從現在開始，你什麼都做不了，只能靜靜看著別人。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"미나 양에게도 이런 방식이 위협이 될 거라고 생각하나?","JPN":"ミナ君にもこんな脅しが通じると思うのか？","ENG":"Do you think your threats will work on Mina too?","TWN":"你覺得這種威脅對米娜也行得通嗎？"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"그들이 나처럼 순순히 당해주진 않을 걸세.","JPN":"彼らは私のようにおとなしくやられたりはしないだろう。","ENG":"They won't cave as easily as I did.","TWN":"她們可不會像我一樣會任你擺布。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시도는 해보겠지만, 저도 그런 늑대가 그 정도 난관에 무너질 거란 기대는 하지 않아요.","JPN":"試してみますけど、私もあの狼がこの程度の試練に負けるとは思っていません。","ENG":"I'll try, but I, too, don't expect the Wolf to be discouraged by such an obstacle.","TWN":"我會嘗試，但我也知道她這種狼不會為這種程度的難關而倒下。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무력한 당신처럼 무한한 시간에 가둬 두고 괴롭힐 순 없겠죠.","JPN":"無力なあなたのように無限の時間に閉じ込め、いじめることもできませんし。","ENG":"Unlike the powerless you, I won't be able to torture her in infinite time.","TWN":"我沒辦法像對付弱小的你一樣把她困在永恆的時間裡。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그건 상관없어요.","JPN":"でも、それは関係ありませんね。","ENG":"Nevertheless, it doesn't matter.","TWN":"但這並不重要。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어차피 제 목적은 그녀들을 굴복시키는 게 아니라 시간을 버는 것뿐이니까요.","JPN":"はなから私の目的は彼女たちを屈服させるのではなく、時間稼ぎですから。","ENG":"My goal isn't to make them surrender to me, but to buy time.","TWN":"我的目的只是爭取時間，而不是制伏她。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼 함께 감상해볼까요? 거울이 그녀들의 무엇을 비추는지.","JPN":"では一緒に見てみましょうか？　鏡が彼女たちの何を映し出すのか。","ENG":"Then, shall we watch together what the mirror will reflect for the girls?","TWN":"我們一起來看看她們的鏡子都照出了什麼。"},"stage":{"bg":"BLACK","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};